class SummaryRanges:

    def __init__(self):
        self.intervals = []

    def addNum(self, value: int) -> None:
        left, right = 0, len(self.intervals) - 1
        while left <= right:
            mid = (left + right) // 2
            start, end = self.intervals[mid]
            if start <= value <= end:
                return
            elif value < start:
                right = mid - 1
            else:
                left = mid + 1
        idx = left
        self.intervals.insert(idx, [value, value])
        if idx > 0 and self.intervals[idx-1][1] + 1 == value:
            self.intervals[idx-1][1] = value
            self.intervals.pop(idx)
            idx -= 1
        if idx < len(self.intervals) - 1 and self.intervals[idx+1][0] - 1 == value:
            self.intervals[idx][1] = self.intervals[idx+1][1]
            self.intervals.pop(idx+1)

    def getIntervals(self) -> List[List[int]]:
        return self.intervals


